from fastapi import APIRouter, Depends, HTTPException
from sqlalchemy.orm import Session
from ..database import get_db
from ..models import User, Report
from .auth import get_current_user
from typing import List, Optional
import json

router = APIRouter(prefix="/api/reports", tags=["reports"])

@router.get("/")
def get_reports(
    db: Session = Depends(get_db),
    current_user: User = Depends(get_current_user)
):
    """Get all reports for the current user"""
    reports = db.query(Report).filter(
        Report.user_id == current_user.id
    ).order_by(Report.created_at.desc()).all()

    return [
        {
            "id": r.id,
            "title": r.title,
            "report_type": r.report_type,
            "data": json.loads(r.data) if r.data else {},
            "created_at": r.created_at.isoformat() if r.created_at else None,
            "updated_at": r.updated_at.isoformat() if r.updated_at else None
        }
        for r in reports
    ]

@router.post("/")
def create_report(
    title: str,
    report_type: str,
    data: dict,
    db: Session = Depends(get_db),
    current_user: User = Depends(get_current_user)
):
    """Create a new report"""
    report = Report(
        title=title,
        report_type=report_type,
        data=json.dumps(data),
        user_id=current_user.id
    )
    db.add(report)
    db.commit()
    db.refresh(report)

    return {
        "id": report.id,
        "title": report.title,
        "report_type": report.report_type,
        "message": "Hisobot yaratildi"
    }

@router.get("/{report_id}")
def get_report(
    report_id: int,
    db: Session = Depends(get_db),
    current_user: User = Depends(get_current_user)
):
    """Get a specific report"""
    report = db.query(Report).filter(
        Report.id == report_id,
        Report.user_id == current_user.id
    ).first()

    if not report:
        raise HTTPException(status_code=404, detail="Hisobot topilmadi")

    return {
        "id": report.id,
        "title": report.title,
        "report_type": report.report_type,
        "data": json.loads(report.data) if report.data else {},
        "created_at": report.created_at.isoformat() if report.created_at else None,
        "updated_at": report.updated_at.isoformat() if report.updated_at else None
    }

@router.put("/{report_id}")
def update_report(
    report_id: int,
    title: Optional[str] = None,
    data: Optional[dict] = None,
    db: Session = Depends(get_db),
    current_user: User = Depends(get_current_user)
):
    """Update a report"""
    report = db.query(Report).filter(
        Report.id == report_id,
        Report.user_id == current_user.id
    ).first()

    if not report:
        raise HTTPException(status_code=404, detail="Hisobot topilmadi")

    if title:
        report.title = title
    if data:
        report.data = json.dumps(data)

    db.commit()
    db.refresh(report)

    return {
        "id": report.id,
        "title": report.title,
        "message": "Hisobot yangilandi"
    }

@router.delete("/{report_id}")
def delete_report(
    report_id: int,
    db: Session = Depends(get_db),
    current_user: User = Depends(get_current_user)
):
    """Delete a report"""
    report = db.query(Report).filter(
        Report.id == report_id,
        Report.user_id == current_user.id
    ).first()

    if not report:
        raise HTTPException(status_code=404, detail="Hisobot topilmadi")

    db.delete(report)
    db.commit()

    return {"message": "Hisobot o'chirildi"}
